// ─────────────────────────────────────────────────────────────────────────────
// GRID CONFIG
// ─────────────────────────────────────────────────────────────────────────────
// Per-cell aspect ratio derived from the original tuned 20/9 container at 5×4.
// (20/9) / (5/4) ≈ 1.778 — keeps individual logo cells the same proportions
// at every breakpoint without needing to guess new container ratios by eye.
const CELL_ASPECT = (20 / 9) / (5 / 4)

const BRAND_COLORS = ["#EB008B", "#FAAF40", "#D6DE23", "#00ADEE", "#885198"]

function hexToRGB(hex: string) {
    const h = hex.replace("#", "")
    return {
        r: parseInt(h.slice(0, 2), 16),
        g: parseInt(h.slice(2, 4), 16),
        b: parseInt(h.slice(4, 6), 16),
    }
}

function lerpRGB(
    a: { r: number; g: number; b: number },
    b: { r: number; g: number; b: number },
    t: number
) {
    return {
        r: Math.round(a.r + (b.r - a.r) * t),
        g: Math.round(a.g + (b.g - a.g) * t),
        b: Math.round(a.b + (b.b - a.b) * t),
    }
}

function bilinearRGB(
    tl: { r: number; g: number; b: number },
    tr: { r: number; g: number; b: number },
    bl: { r: number; g: number; b: number },
    br: { r: number; g: number; b: number },
    tx: number,
    ty: number
) {
    const top = lerpRGB(tl, tr, tx)
    const bot = lerpRGB(bl, br, tx)
    return lerpRGB(top, bot, ty)
}
// ─────────────────────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────────────────────
function shuffle<T>(arr: T[]): T[] {
    const a = [...arr]
    for (let i = a.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1))
        ;[a[i], a[j]] = [a[j], a[i]]
    }
    return a
}

function distFromCenter(i: number, cols: number, rows: number): number {
    const col = i % cols
    const row = Math.floor(i / cols)
    const cx = (cols - 1) / 2
    const cy = (rows - 1) / 2
    return Math.sqrt((col - cx) ** 2 + (row - cy) ** 2)
}

function settleEasing(elasticity: number): string {
    const c2 = Math.min(elasticity - 1.0, 0.9)
    return `cubic-bezier(0.34, ${c2.toFixed(2)}, 0.64, 1)`
}

function getFillEls(cell: HTMLElement) {
    return {
        fills: [
            ...cell.querySelectorAll<SVGElement>(
                'svg [fill]:not([fill="none"])'
            ),
        ],
        strokes: [
            ...cell.querySelectorAll<SVGElement>(
                'svg [stroke]:not([stroke="none"])'
            ),
        ],
    }
}

function entranceScale(
    svg: SVGElement,
    fromScale: number,
    overshoot: number,
    fadeDur: number,
    delay: number,
    elasticity: number
) {
    svg.style.transform = `scale(${fromScale})`
    svg.style.transition = "none"
    const t1 = fadeDur * 0.55
    const t2 = fadeDur * 0.45
    setTimeout(() => {
        svg.style.transition = `transform ${t1}ms ${TIMING.easeOut}`
        svg.style.transform = `scale(${overshoot})`
        setTimeout(() => {
            svg.style.transition = `transform ${t2}ms ${settleEasing(elasticity)}`
            svg.style.transform = "scale(1)"
        }, t1)
    }, delay)
}

// ─────────────────────────────────────────────────────────────────────────────
// COMPONENT
// ─────────────────────────────────────────────────────────────────────────────
interface Props {
    gap?: number
    logoSizePercent?: number
    triggerOnScroll?: boolean
    onComplete?: () => void
}

export default function ClientLogoGrid({
    gap = 16,
    logoSizePercent = 70,
    triggerOnScroll = false,
    onComplete,
}: Props) {
    const gridRef = useRef<HTMLDivElement>(null)
    const hasAnimated = useRef(false)

    const breakpoint = useBreakpoint()
    const { cols, rows } = LOGO_GRID_TIERS[breakpoint]
    const count = cols * rows
    const containerAspect = (cols / rows) * CELL_ASPECT

    const runAnimation = useCallback(
        (grid: HTMLDivElement) => {
            if (!grid) return

            grid.style.opacity = "0"
            grid.style.transition = "none"
            grid.querySelectorAll<SVGElement>("[fill]").forEach((el) => {
                el.style.fill = "transparent"
            })
            grid.querySelectorAll<SVGElement>("[stroke]").forEach((el) => {
                el.style.stroke = "transparent"
            })
            grid.innerHTML = ""

            const {
                spreadMs,
                jitterMs,
                fadeDurMs,
                settleMs,
                scaleStart,
                overshoot,
                elasticity,
                lingerMs,
                hoverScale,
            } = DEFAULTS

            const maxDist = distFromCenter(0, cols, rows)

            // Pick count logos at random from full pool
            const picked = shuffle([...Array(LOGOS.length).keys()]).slice(
                0,
                count
            )
            const order = shuffle(picked)
            const shuffled = shuffle([...BRAND_COLORS])
            const cornerTL = hexToRGB(shuffled[0])
            const cornerTR = hexToRGB(shuffled[1])
            const cornerBL = hexToRGB(shuffled[2])
            const cornerBR = hexToRGB(shuffled[3])
            const endColor = "hsl(0 0% 90%)"

            order.forEach((logoIdx, gridPos) => {
                const logo = LOGOS[logoIdx]
                const col = gridPos % cols
                const row = Math.floor(gridPos / cols)
                const tx = cols > 1 ? col / (cols - 1) : 0
                const ty = rows > 1 ? row / (rows - 1) : 0
                const rgb = bilinearRGB(
                    cornerTL,
                    cornerTR,
                    cornerBL,
                    cornerBR,
                    tx,
                    ty
                )
                const hue = `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`
                const startColor = hue

                const cell = document.createElement("div")
                cell.style.cssText = `
                aspect-ratio: 16/9;
                display: flex;
                align-items: center;
                justify-content: center;
                opacity: 0;
                cursor: default;
            `
                cell.dataset.hue = String(hue)

                cell.innerHTML = `<svg viewBox="${logo.viewBox}" xmlns="http://www.w3.org/2000/svg" style="width:${logoSizePercent}%;height:${logoSizePercent}%;transform:scale(${scaleStart});transition:none;">${logo.svg}</svg>`

                // Swap white fills to entrance hue colour
                const svgEl = cell.querySelector("svg")!
                svgEl.querySelectorAll<SVGElement>("[fill]").forEach((el) => {
                    const f = el.getAttribute("fill") ?? ""
                    if (
                        [
                            "#fff",
                            "#ffffff",
                            "#FFF",
                            "#FFFFFF",
                            "white",
                        ].includes(f)
                    ) {
                        el.setAttribute("fill", startColor)
                    }
                })

                const dist = distFromCenter(gridPos, cols, rows)
                const delay =
                    (dist / maxDist) * spreadMs + Math.random() * jitterMs
                grid.appendChild(cell)

                // Fade in + colour settle
                setTimeout(() => {
                    cell.style.transition = `opacity ${fadeDurMs}ms ease`
                    cell.style.opacity = "1"
                    const { fills, strokes } = getFillEls(cell)
                    fills.forEach((el) => {
                        el.style.transition = `fill ${settleMs}ms ease ${fadeDurMs * 0.6}ms`
                        el.style.fill = endColor
                    })
                    strokes.forEach((el) => {
                        el.style.transition = `stroke ${settleMs}ms ease ${fadeDurMs * 0.6}ms`
                        el.style.stroke = endColor
                    })
                }, delay)

                entranceScale(
                    svgEl,
                    scaleStart,
                    overshoot,
                    fadeDurMs,
                    delay,
                    elasticity
                )

                // Hover
                const hoverColor = `hsl(${hue} 75% 62%)`
                let lingerTimer: ReturnType<typeof setTimeout> | null = null
            })

            // Fire onComplete after last logo has landed
            const maxDelay = spreadMs + jitterMs + fadeDurMs
            setTimeout(() => onComplete?.(), maxDelay + 300)

            // Document-level hover — Framer iframe blocks element-level mouse events
            const handleMouseMove = (e: MouseEvent) => {
                grid.querySelectorAll<HTMLElement>("[data-hue]").forEach(
                    (cell) => {
                        const rect = cell.getBoundingClientRect()
                        const inside =
                            e.clientX >= rect.left &&
                            e.clientX <= rect.right &&
                            e.clientY >= rect.top &&
                            e.clientY <= rect.bottom

                        const hue = cell.dataset.hue!
                        const hoverColor = hue
                        const endColor = "hsl(0 0% 90%)"
                        const svgEl = cell.querySelector("svg") as SVGElement

                        if (inside && cell.dataset.hovered !== "true") {
                            cell.dataset.hovered = "true"
                            const { fills, strokes } = getFillEls(cell)
                            fills.forEach((el) => {
                                el.style.transition = "fill 0.2s ease"
                                el.style.fill = hoverColor
                            })
                            strokes.forEach((el) => {
                                el.style.transition = "stroke 0.2s ease"
                                el.style.stroke = hoverColor
                            })
                            if (svgEl && hoverScale > 1.001) {
                                svgEl.style.transition = `transform 0.18s ${TIMING.easeSpringOver}`
                                svgEl.style.transform = `scale(${hoverScale})`
                            }
                        } else if (!inside && cell.dataset.hovered === "true") {
                            cell.dataset.hovered = "false"
                            setTimeout(() => {
                                const { fills, strokes } = getFillEls(cell)
                                fills.forEach((el) => {
                                    el.style.transition = `fill ${lingerMs}ms ease`
                                    el.style.fill = endColor
                                })
                                strokes.forEach((el) => {
                                    el.style.transition = `stroke ${lingerMs}ms ease`
                                    el.style.stroke = endColor
                                })
                                if (svgEl) {
                                    svgEl.style.transition = `transform ${lingerMs * 0.6}ms ${settleEasing(elasticity)}`
                                    svgEl.style.transform = "scale(1)"
                                }
                            }, 80)
                        }
                    }
                )
            }

            document.addEventListener("mousemove", handleMouseMove)
            return () =>
                document.removeEventListener("mousemove", handleMouseMove)
        },
        [logoSizePercent, cols, rows, count]
    )

    useEffect(() => {
        const grid = gridRef.current
        if (!grid) return

        if (!triggerOnScroll) {
            runAnimation(grid)
            return
        }

        let animTriggered = false
        let resetTimer: ReturnType<typeof setTimeout> | null = null

        function handleScroll() {
            const grid = gridRef.current
            if (!grid) return

            const rect = grid.getBoundingClientRect()
            const viewH = window.innerHeight
            const distFromBottom =
                viewH - rect.bottom + (rect.bottom - rect.top) * 0.5
            const raw =
                (distFromBottom - SCROLL_FADE.fadeInStart) /
                (SCROLL_FADE.fadeInEnd - SCROLL_FADE.fadeInStart)
            const opacity = Math.max(0, Math.min(1, raw))

            if (animTriggered) {
                grid.style.opacity = String(opacity)
            }

            if (opacity === 0 && animTriggered) {
                if (!resetTimer) {
                    resetTimer = setTimeout(() => {
                        animTriggered = false
                        // Clear grid contents while invisible
                        grid.innerHTML = ""
                        resetTimer = null
                    }, 650)
                }
            } else {
                if (resetTimer) {
                    clearTimeout(resetTimer)
                    resetTimer = null
                }
            }

            if (opacity > 0 && !animTriggered) {
                animTriggered = true
                grid.style.transition = "none"
                grid.style.opacity = "1"
                runAnimation(grid)
                setTimeout(() => {
                    grid.style.transition = `opacity 600ms ${TIMING.easeSpring}`
                }, SCROLL_FADE.animDelay + 100)
            }
        }

        window.addEventListener("scroll", handleScroll, { passive: true })
        return () => window.removeEventListener("scroll", handleScroll)
    }, [runAnimation, triggerOnScroll])

    return (
        <div
            style={{
                position: "relative",
                width: "100%",
                aspectRatio: containerAspect,
            }}
        >
            <div
                ref={gridRef}
                style={{
                    position: "absolute",
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    display: "grid",
                    gridTemplateColumns: `repeat(${cols}, 1fr)`,
                    gap,
                    opacity: 0,
                }}
            />
        </div>
    )
}

